import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Dashboard from './pages/Dashboard';
import Recommendations from './pages/Recommendations'; // Still used for a dedicated page if needed
import LandingPage from './pages/LandingPage'; // <--- NEW IMPORT
import api from './api/api'; 

const App = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [profile, setProfile] = useState({});
  const [appLoading, setAppLoading] = useState(true);

  const handleAuth = (token, profileData) => {
    localStorage.setItem('token', token);
    setIsLoggedIn(true);
    setProfile(profileData || {});
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setIsLoggedIn(false);
    setProfile({});
  };
  
  const fetchProfileData = async () => {
    if (!localStorage.getItem('token')) {
        setAppLoading(false);
        return;
    }
    try {
        const response = await api.get('/profile');
        setProfile(response.data.profile);
    } catch (err) {
        handleLogout(); 
    } finally {
        setAppLoading(false);
    }
  };

  useEffect(() => {
    if (localStorage.getItem('token')) {
      setIsLoggedIn(true);
      fetchProfileData(); 
    } else {
      setAppLoading(false);
    }
  }, [isLoggedIn]); 

  // Protected Route Wrapper
  const ProtectedRoute = ({ children }) => {
    if (!isLoggedIn) {
      return <Navigate to="/" replace />;
    }
    return children;
  };
  
  if (appLoading) {
      return <div className="min-h-screen bg-[#121212] text-ai-green text-center text-2xl font-bold pt-40">Loading Application Data...</div>;
  }

  return (
    <Router>
        {/* Top Navbar Section (Handles the Login/About/Title Bar) */}
        <header className="bg-[#1E1E1E] shadow-ai text-white p-4 flex justify-between items-center border-b border-[#00AEEF]">
            <div className="flex items-center">
                <h1 className="text-xl font-bold text-ai-green">
                    AI-Powered Fitness System
                </h1>
            </div>
            <nav className="flex space-x-6 text-sm">
                <a href="/about" className="text-gray-300 hover:text-ai-green transition">About</a>
                {isLoggedIn ? (
                    <button onClick={handleLogout} className="text-red-400 hover:text-red-300 transition font-medium">Logout</button>
                ) : (
                    <a href="/" className="text-white hover:text-ai-green transition font-medium">Login</a>
                )}
            </nav>
        </header>

        <Routes>
          {/* Landing Page is now the default public route */}
          <Route path="/" element={isLoggedIn ? <Navigate to="/dashboard" /> : <LandingPage onAuthSuccess={handleAuth} />} />
          
          <Route path="/dashboard" element={
            <ProtectedRoute>
              {/* Dashboard is the main sidebar layout */}
              <Dashboard profile={profile} setProfile={setProfile} fetchProfile={fetchProfileData} /> 
            </ProtectedRoute>
          } />
          
          {/* Keep Recommendations route for direct navigation, although it's mostly inside Dashboard now */}
          <Route path="/recommendations" element={
            <ProtectedRoute>
              <Recommendations profile={profile} />
            </ProtectedRoute>
          } />
          
          <Route path="/about" element={<div className="p-8 text-white">About Page Content (To be filled)</div>} />
          <Route path="*" element={<Navigate to="/dashboard" />} />
        </Routes>
    </Router>
  );
};

export default App;
